+#[test]
+fn test_thrd_sleep_zero_duration() {
+    unsafe {
+        let dur = libc::timespec {
+            tv_sec: 0,
+            tv_nsec: 0,
+        };
+        let rc = thrd_sleep(&dur, std::ptr::null_mut());
+        assert_eq!(rc, 0, "thrd_sleep(0) should return 0");
+    }
+}
