+    unsafe {
+        let dur = libc::timespec {
+            tv_sec: 0,
+            tv_nsec: 1_000_000,
+        }; // 1ms
+        let mut rem: libc::timespec = std::mem::zeroed();
+        let rc = thrd_sleep(&dur, &mut rem);
+        assert_eq!(rc, 0);
