+#[test]
+fn ctype_b_loc_digit_bits() {
+    let pp = unsafe { __ctype_b_loc() };
+    let p = unsafe { *pp };
+    for d in b'0'..=b'9' {
+        let flags = unsafe { *p.offset(d as isize) };
